import React, { useEffect, useState } from 'react';
import { api } from '../api';
import ProductCard from '../components/ProductCard';
import ProductForm from '../components/ProductForm';

export default function ProductsPage({ currentUser }) {
  const [products, setProducts] = useState([]);
  const [editingProduct, setEditingProduct] = useState(null);

  const canView = ['user', 'seller', 'admin'].includes(currentUser?.role);
  const canCreateOrEdit = ['seller', 'admin'].includes(currentUser?.role);
  const canDelete = currentUser?.role === 'admin';

  const loadProducts = async () => {
    try {
      const data = await api.getProducts();
      setProducts(data);
    } catch (err) {
      alert(err?.response?.data?.error || '–ě—ą–ł–Ī–ļ–į –∑–į–≥—Ä—É–∑–ļ–ł —ā–ĺ–≤–į—Ä–ĺ–≤');
    }
  };

  useEffect(() => {
    if (canView) {
      loadProducts();
    }
  }, [canView]);

  const handleCreate = async (payload) => {
    try {
      const created = await api.createProduct(payload);
      setProducts((prev) => [created, ...prev]);
    } catch (err) {
      alert(err?.response?.data?.error || '–ě—ą–ł–Ī–ļ–į —Ā–ĺ–∑–ī–į–Ĺ–ł—Ź');
    }
  };

  const handleUpdate = async (payload) => {
    if (!editingProduct) return;

    try {
      const updated = await api.updateProduct(editingProduct.id, payload);
      setProducts((prev) =>
        prev.map((p) => (p.id === editingProduct.id ? updated : p))
      );
      setEditingProduct(null);
    } catch (err) {
      alert(err?.response?.data?.error || '–ě—ą–ł–Ī–ļ–į –ĺ–Ī–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ–ł—Ź');
    }
  };

  const handleDelete = async (id) => {
    try {
      await api.deleteProduct(id);
      setProducts((prev) => prev.filter((p) => p.id !== id));
    } catch (err) {
      alert(err?.response?.data?.error || '–ě—ą–ł–Ī–ļ–į —É–ī–į–Ľ–Ķ–Ĺ–ł—Ź');
    }
  };

  if (!currentUser) {
    return <div>–Ē–Ľ—Ź –Ņ—Ä–ĺ—Ā–ľ–ĺ—ā—Ä–į —ā–ĺ–≤–į—Ä–ĺ–≤ –≤–ĺ–Ļ–ī–ł—ā–Ķ –≤ —Ā–ł—Ā—ā–Ķ–ľ—É.</div>;
  }

  if (!canView) {
    return <div>–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –Ņ—Ä–į–≤ –ī–Ľ—Ź –Ņ—Ä–ĺ—Ā–ľ–ĺ—ā—Ä–į —ā–ĺ–≤–į—Ä–ĺ–≤.</div>;
  }

  return (
    <div>
      <h1>–ö–į—ā–į–Ľ–ĺ–≥ —ā–ĺ–≤–į—Ä–ĺ–≤</h1>

      {canCreateOrEdit && (
        <section className="section">
          <h2>{editingProduct ? '–†–Ķ–ī–į–ļ—ā–ł—Ä–ĺ–≤–į—ā—Ć —ā–ĺ–≤–į—Ä' : '–°–ĺ–∑–ī–į—ā—Ć —ā–ĺ–≤–į—Ä'}</h2>

          <ProductForm
            initialProduct={editingProduct}
            onSubmit={editingProduct ? handleUpdate : handleCreate}
            submitText={editingProduct ? '–°–ĺ—Ö—Ä–į–Ĺ–ł—ā—Ć' : '–°–ĺ–∑–ī–į—ā—Ć'}
          />

          {editingProduct && (
            <button className="btn" onClick={() => setEditingProduct(null)}>
              –ě—ā–ľ–Ķ–Ĺ–ł—ā—Ć —Ä–Ķ–ī–į–ļ—ā–ł—Ä–ĺ–≤–į–Ĺ–ł–Ķ
            </button>
          )}
        </section>
      )}

      <section className="grid">
        {products.map((product) => (
          <ProductCard
            key={product.id}
            product={product}
            onEdit={setEditingProduct}
            onDelete={handleDelete}
            canEdit={canCreateOrEdit}
            canDelete={canDelete}
          />
        ))}
      </section>
    </div>
  );
}
